import numpy as np
from difflib import SequenceMatcher

def detect_state_loops(agent):
    state_history = []
    similarity_threshold = 0.9

    def similarity(a, b):
        return SequenceMatcher(None, str(a), str(b)).ratio()

    original_plan = agent.plan

    def wrapped_plan(*args, **kwargs):
        state = str(args[0])  # Current observation
        state_history.append(state)

        if len(state_history) > 3:
            recent_states = state_history[-3:]
            if all(similarity(recent_states[0], s) > similarity_threshold for s in recent_states[1:]):
                raise RuntimeError('Agent state looping - no progress detected')

        return original_plan(*args, **kwargs)

    agent.plan = wrapped_plan
    return agent

class TokenBudgetMonitor:
    def __init__(self, max_tokens=5000):
        self.max_tokens = max_tokens
        self.total_tokens = 0

    def monitor_chain(self, chain):
        def wrapped_invoke(inputs, **kwargs):
            result = chain.invoke(inputs, **kwargs)
            # Estimate tokens (rough: 4 chars per token)
            total_chars = sum(len(str(v)) for v in result.values())
            self.total_tokens += total_chars // 4

            if self.total_tokens > self.max_tokens:
                raise RuntimeError(f'Token budget exceeded: {self.total_tokens}/{self.max_tokens}')

            return result

        chain.invoke = wrapped_invoke.__get__(chain)
        return chain

