from collections import defaultdict, deque
import hashlib

class LoopProofAgentExecutor(AgentExecutor):
    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self.tool_cache = defaultdict(deque)
        self.cache_window = 5

    def _call(self, *args, **kwargs):
        # Hash tool input for deduplication
        tool_input = str(kwargs.get('tool_input', ''))
        tool_hash = hashlib.md5(tool_input.encode()).hexdigest()

        if tool_hash in [h for h in self.tool_cache[kwargs.get('tool', 'unknown')]][:self.cache_window]:
            return {'output': 'Tool call skipped - recent duplicate detected'}

        self.tool_cache[kwargs.get('tool', 'unknown')].append(tool_hash)
        if len(self.tool_cache[kwargs.get('tool', 'unknown')]) > self.cache_window:
            self.tool_cache[kwargs.get('tool', 'unknown')].popleft()

        return super()._call(*args, **kwargs)

from langchain.schema import AgentAction, AgentFinish

def confident_early_stop(agent):
    def wrapped_agent(inputs):
        response = agent(inputs)
        # Check for confident final answer patterns
        confident_phrases = ['final answer', 'conclusion', 'result is', 'answer:']

        if isinstance(response, AgentFinish):
            content = response.return_values['output'].lower()
            if any(phrase in content for phrase in confident_phrases):
                return response

        return response

    return wrapped_agent
